var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"하아아압!","JPN":"はあああ！","ENG":"Haaah!","TWN":"嚇啊啊啊！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"이쪽은 아직 괜찮습니다. 다른 쪽 상황은 어떤가요?","JPN":"こっちはまだ行けます。他のところの状況はどうですか？","ENG":"Things are fine over here. How is everyone else doing?","TWN":"這邊目前還好，另一邊情況如何？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"이쪽도 문제없어.","JPN":"こちらも問題ない。","ENG":"I am fine here as well.","TWN":"這邊也沒問題。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"몇 마리 놓치긴 했지만, 성녀가 감당하지 못할 수는 아니야.","JPN":"何匹か逃したが、聖女の手に負えないほどではない。","ENG":"A few monsters got away, but nothing the Saintess cannot handle.","TWN":"雖然放走幾隻，但聖女應該能應付。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"그래서 구원자. 지금까지 총 몇 마리를 쓰러트렸지?","JPN":"それで、救世主。今まで何匹倒した？","ENG":"So, Savior. How many have you vanquished so far?","TWN":"所以，救贖者大人目前為止總共擊殺多少隻？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"참고로 난 열 두 마리 째야.","JPN":"ちなみに、私は12匹目だ。","ENG":"I am on my 12th at the moment.","TWN":"順便說一句，我目前已經擊殺12隻。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"미안. 이번에도 세는 걸 까먹었어.","JPN":"ごめん。今度も数えるのを忘れてたよ。","ENG":"Sorry. I forgot to count again.","TWN":"抱歉，這次又忘記數。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"지휘관이라도 된 양 떠들지 마라, 평민. 넌 내가 시키는 대로만 하면 그만이야.","JPN":"指揮官にでもなったかのように騒ぐな、平民。貴様は私の指示どおりに動いていればいい。","ENG":"Do not yap like you are the commanding officer, peasant. Do as I say, and nothing else.","TWN":"別像個指揮官一樣大呼小叫的，平民。你只要聽我指揮就好。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"부상자들은 교대하며 전선을 유지하도록.","JPN":"怪我人は交代し、戦線を維持しろ。","ENG":"The injured are to maintain the line by switching out.","TWN":"傷者輪流上場，守住戰線。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"다음은 없으니, 이곳에서 결판을 지어야 한다!","JPN":"次などない、ここで決着をつけるのだ！","ENG":"There will be no second chance. We need to end this here!","TWN":"沒有下一次的機會，必須在這裡定勝負！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"허억… 허억…","JPN":"はあ……はあ……","ENG":"*Huff...* *Huff...*","TWN":"呼呼…呼呼…"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"괜찮으신가요?","JPN":"大丈夫ですか？","ENG":"Are you all right?","TWN":"你沒事吧？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"괘, 괜찮습니다. 아직 싸울 수 있습니다!","JPN":"だ、大丈夫です。まだ戦えます！","ENG":"I-I'm all right. I can still fight!","TWN":"還，還好，還能打！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"부상의 정도가 심합니다. 너무 무리하지 마세요.","JPN":"かなり怪我をされています。あまり無理しないでください。","ENG":"You're severely injured. Don't overdo yourself.","TWN":"你的傷勢很嚴重，不要太勉強自己。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"죄송합니다. 저희가 약한 탓에 구원자님께 민폐를 끼치는군요.","JPN":"申し訳ありません。俺たちが弱いせいで救世主様にご迷惑をおかけしますね。","ENG":"Forgive us. We're too weak, and nothing but an inconvenience to you.","TWN":"抱歉，都是我們太弱，拖累救贖者大人。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"그런 말씀 마세요. 여러분들을 지키는 게 구원자로서의 제 사명이니까요.","JPN":"そんなこと言わないでください。皆さんを守るのが、救世主としての僕の使命ですから。","ENG":"Don't say that. It's my duty as the Savior to protect you all.","TWN":"別這麼說。保護大家是我深為救贖者的使命。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"…점점 부상자들이 늘고 있어.","JPN":"……どんどん怪我人が増えてる。","ENG":"...More people are getting injured by the minute.","TWN":"…傷者越來越多。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"마을에 기사들이 남아있다 해도, 이대로 시간이 끌렸다간 위험할지도 몰라.","JPN":"村に騎士が残っているって言っても、このまま長引くと危ないかもしれない。","ENG":"There are some knights in the village, but it might get dangerous if we keep losing time.","TWN":"就算村莊裡有騎士團，這樣下去時間拉長會有危險。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"루크레시아는… 괜찮겠지?","JPN":"ルクレシアは……大丈夫だよね？","ENG":"I hope... Lucrecia is safe.","TWN":"露可蕾西亞…應該沒問題吧？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"구원자님! 큰일입니다!","JPN":"救世主様！　大変です！","ENG":"Savior! There's a problem!","TWN":"救贖者大人！大事不妙！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"남북쪽 방향의 길이 뚫렸습니다. 대장님이 당하셨어요!","JPN":"南北方向の道を突破されました。隊長がやられて！","ENG":"The monsters broke through the southern routes. Our captain is down!","TWN":"南北二邊的路被突圍，隊長也遭到怪獸的攻擊！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};